import React, { useState, useRef, useEffect, useMemo } from 'react';

const theme = {
  bg: '#0a0a0a',
  surface: '#141414',
  surfaceAlt: '#1a1a1a',
  border: '#262626',
  text: '#fafafa',
  textSec: '#a1a1aa',
  muted: '#52525b',
  blue: '#38bdf8',
  pink: '#f472b6',
  green: '#a3e635',
  primary: '#8b5cf6',
  red: '#f43f5e',
  font: "'JetBrains Mono', monospace",
};

const PRESETS = [
  { name: 'Simple', a: [1, 3, 5], b: [4, 2, 6] },
  { name: 'Negatives', a: [3, -2, 7, 1], b: [-1, 4, -3, 2] },
  { name: 'Mismatch!', a: [1, 2], b: [3, 4, 5] },
];

function EditableCell({ value, color, highlight, onCommit, glowColor }) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState('');
  const ref = useRef(null);

  useEffect(() => {
    if (editing && ref.current) {
      ref.current.focus();
      ref.current.select();
    }
  }, [editing]);

  const commit = () => {
    const num = parseFloat(draft);
    if (!isNaN(num)) onCommit(Math.round(num * 10) / 10);
    setEditing(false);
  };

  if (editing) {
    return (
      <input
        ref={ref}
        value={draft}
        onChange={e => setDraft(e.target.value)}
        onBlur={commit}
        onKeyDown={e => { if (e.key === 'Enter') commit(); if (e.key === 'Escape') setEditing(false); }}
        style={{
          width: 52, height: 52, textAlign: 'center', fontSize: 16, fontWeight: 700,
          fontFamily: theme.font, background: theme.surfaceAlt, color: theme.text,
          border: '2px solid ' + color, borderRadius: 10, outline: 'none',
        }}
      />
    );
  }

  return (
    <div
      onClick={() => { setDraft(String(value)); setEditing(true); }}
      style={{
        width: 52, height: 52, display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 16, fontWeight: 700, fontFamily: theme.font, color: theme.text,
        background: highlight ? color + '20' : theme.surfaceAlt,
        border: '2px solid ' + (highlight ? color : theme.border),
        borderRadius: 10, cursor: 'pointer', transition: 'all 0.3s ease',
        boxShadow: highlight && glowColor ? '0 0 14px ' + glowColor + '33' : 'none',
      }}
    >
      {value}
    </div>
  );
}

function ResultCell({ value, highlight }) {
  return (
    <div style={{
      width: 52, height: 52, display: 'flex', alignItems: 'center', justifyContent: 'center',
      fontSize: 16, fontWeight: 700, fontFamily: theme.font,
      color: highlight ? theme.green : theme.text,
      background: highlight ? theme.green + '18' : theme.surface,
      border: '2px solid ' + (highlight ? theme.green : theme.border),
      borderRadius: 10, transition: 'all 0.3s ease',
      boxShadow: highlight ? '0 0 16px ' + theme.green + '30' : 'none',
    }}>
      {value}
    </div>
  );
}

function SizeBtn({ label, onClick, disabled }) {
  return (
    <div
      onClick={disabled ? undefined : onClick}
      style={{
        width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 16, fontWeight: 600, fontFamily: theme.font,
        color: disabled ? theme.muted : theme.textSec,
        background: theme.surfaceAlt, border: '1px solid ' + theme.border,
        borderRadius: 6, cursor: disabled ? 'default' : 'pointer',
        opacity: disabled ? 0.4 : 1, transition: 'all 0.2s',
      }}
    >
      {label}
    </div>
  );
}

function BarChart({ vecA, vecB, result, hoveredCol, setHoveredCol, isValid }) {
  const maxCols = Math.max(vecA.length, vecB.length);
  const allVals = [...vecA, ...vecB, ...(result || [])];
  const absMax = Math.max(Math.abs(Math.min(...allVals, 0)), Math.abs(Math.max(...allVals, 0)), 1);
  const svgW = 540;
  const svgH = 170;
  const padX = 40;
  const padT = 16;
  const padB = 24;
  const plotH = svgH - padT - padB;
  const baseY = padT + plotH * (absMax / (2 * absMax));
  const groupW = Math.min(80, (svgW - 2 * padX) / maxCols);
  const barW = Math.min(14, (groupW - 12) / 3);
  const scale = (v) => (v / absMax) * (plotH / 2);

  return (
    <svg width="100%" viewBox={`0 0 ${svgW} ${svgH}`} style={{ display: 'block' }}>
      {/* baseline */}
      <line x1={padX - 10} y1={baseY} x2={svgW - padX + 10} y2={baseY}
        stroke={theme.border} strokeWidth={1} />
      <text x={padX - 14} y={baseY + 4} fontSize={9} fill={theme.muted}
        fontFamily={theme.font} textAnchor="end">0</text>

      {Array.from({ length: maxCols }).map((_, i) => {
        const cx = padX + i * groupW + groupW / 2;
        const aVal = i < vecA.length ? vecA[i] : null;
        const bVal = i < vecB.length ? vecB[i] : null;
        const rVal = result && i < result.length ? result[i] : null;
        const hl = hoveredCol === i;

        return (
          <g key={i}
            onMouseEnter={() => setHoveredCol(i)}
            onMouseLeave={() => setHoveredCol(null)}
            style={{ cursor: 'default' }}
          >
            {/* hover background */}
            <rect x={cx - groupW / 2 + 2} y={padT - 4}
              width={groupW - 4} height={plotH + 8}
              rx={6} fill={hl ? theme.text + '06' : 'transparent'}
              style={{ transition: 'fill 0.2s' }} />

            {/* a bar */}
            {aVal !== null && (
              <rect
                x={cx - barW * 1.5 - 2} y={aVal >= 0 ? baseY - scale(aVal) : baseY}
                width={barW} height={Math.abs(scale(aVal)) || 1}
                rx={3} fill={hl ? theme.blue : theme.blue + '70'}
                style={{ transition: 'all 0.4s ease' }} />
            )}
            {/* b bar */}
            {bVal !== null && (
              <rect
                x={cx - barW / 2} y={bVal >= 0 ? baseY - scale(bVal) : baseY}
                width={barW} height={Math.abs(scale(bVal)) || 1}
                rx={3} fill={hl ? theme.pink : theme.pink + '70'}
                style={{ transition: 'all 0.4s ease' }} />
            )}
            {/* result bar */}
            {rVal !== null && (
              <rect
                x={cx + barW / 2 + 2} y={rVal >= 0 ? baseY - scale(rVal) : baseY}
                width={barW} height={Math.abs(scale(rVal)) || 1}
                rx={3} fill={hl ? theme.green : theme.green + '70'}
                style={{ transition: 'all 0.4s ease' }} />
            )}

            {/* index label */}
            <text x={cx} y={svgH - 4} fontSize={10} fill={hl ? theme.text : theme.muted}
              fontFamily={theme.font} textAnchor="middle"
              style={{ transition: 'fill 0.2s' }}>
              [{i}]
            </text>

            {/* dimension mismatch indicator */}
            {!isValid && ((i >= vecA.length) || (i >= vecB.length)) && (
              <text x={cx} y={baseY - 8} fontSize={16} fill={theme.red}
                textAnchor="middle" fontFamily={theme.font}>?</text>
            )}
          </g>
        );
      })}
    </svg>
  );
}

export default function App() {
  const [vecA, setVecA] = useState([1, 3, 5]);
  const [vecB, setVecB] = useState([4, 2, 6]);
  const [hoveredCol, setHoveredCol] = useState(null);

  const isValid = vecA.length === vecB.length;
  const result = isValid ? vecA.map((v, i) => v + vecB[i]) : null;
  const maxCols = Math.max(vecA.length, vecB.length);

  const updateA = (idx, val) => setVecA(prev => prev.map((v, i) => i === idx ? val : v));
  const updateB = (idx, val) => setVecB(prev => prev.map((v, i) => i === idx ? val : v));

  const insight = useMemo(() => {
    if (!isValid) {
      return `Vectors have different lengths (${vecA.length} vs ${vecB.length}). Element-wise sum is undefined - returns -1.`;
    }
    if (hoveredCol !== null && hoveredCol < vecA.length) {
      const i = hoveredCol;
      const a = vecA[i], b = vecB[i], r = result[i];
      return `Index ${i}:  ${a} + ${b} = ${r}`;
    }
    const hasNeg = vecA.some(v => v < 0) || vecB.some(v => v < 0);
    if (hasNeg) return 'Negative values work too. Each pair of elements is summed independently.';
    return `Click any value in a or b to edit it. Hover columns to inspect.`;
  }, [vecA, vecB, result, hoveredCol, isValid]);

  return (
    <div style={{
      minHeight: '100vh', background: theme.bg, color: theme.text,
      fontFamily: theme.font, display: 'flex', justifyContent: 'center',
      padding: '24px 16px', boxSizing: 'border-box',
    }}>
      <div style={{ width: '100%', maxWidth: 580 }}>
        {/* Header */}
        <div style={{ marginBottom: 20 }}>
          <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 12 }}>
            Vector Element-wise Sum
          </div>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {PRESETS.map(p => (
              <div key={p.name}
                onClick={() => { setVecA([...p.a]); setVecB([...p.b]); setHoveredCol(null); }}
                style={{
                  padding: '5px 14px', fontSize: 11, fontWeight: 600,
                  background: theme.surfaceAlt, border: '1px solid ' + theme.border,
                  borderRadius: 6, cursor: 'pointer', color: theme.textSec,
                  transition: 'all 0.2s',
                }}
                onMouseEnter={e => { e.target.style.borderColor = theme.primary; e.target.style.color = theme.text; }}
                onMouseLeave={e => { e.target.style.borderColor = theme.border; e.target.style.color = theme.textSec; }}
              >
                {p.name}
              </div>
            ))}
          </div>
        </div>

        {/* Vector grid */}
        <div style={{
          background: theme.surface, borderRadius: 14, padding: '20px 16px',
          border: '1px solid ' + theme.border,
        }}>
          {/* Vector A row */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
            <div style={{
              width: 32, fontSize: 13, fontWeight: 700, color: theme.blue, textAlign: 'right',
            }}>a =</div>
            <div style={{ display: 'flex', gap: 6, flex: 1, flexWrap: 'wrap' }}>
              {vecA.map((v, i) => (
                <div key={i}
                  onMouseEnter={() => setHoveredCol(i)}
                  onMouseLeave={() => setHoveredCol(null)}
                >
                  <EditableCell value={v} color={theme.blue}
                    highlight={hoveredCol === i}
                    glowColor={theme.blue}
                    onCommit={val => updateA(i, val)} />
                </div>
              ))}
            </div>
            <div style={{ display: 'flex', gap: 3 }}>
              <SizeBtn label="+" onClick={() => vecA.length < 6 && setVecA([...vecA, 0])} disabled={vecA.length >= 6} />
              <SizeBtn label="-" onClick={() => vecA.length > 1 && setVecA(vecA.slice(0, -1))} disabled={vecA.length <= 1} />
            </div>
          </div>

          {/* Plus signs */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
            <div style={{ width: 32 }} />
            <div style={{ display: 'flex', gap: 6 }}>
              {Array.from({ length: maxCols }).map((_, i) => (
                <div key={i} style={{
                  width: 52, textAlign: 'center', fontSize: 18, fontWeight: 400,
                  color: hoveredCol === i ? theme.text : theme.muted,
                  transition: 'color 0.3s',
                }}>+</div>
              ))}
            </div>
          </div>

          {/* Vector B row */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
            <div style={{
              width: 32, fontSize: 13, fontWeight: 700, color: theme.pink, textAlign: 'right',
            }}>b =</div>
            <div style={{ display: 'flex', gap: 6, flex: 1, flexWrap: 'wrap' }}>
              {vecB.map((v, i) => (
                <div key={i}
                  onMouseEnter={() => setHoveredCol(i)}
                  onMouseLeave={() => setHoveredCol(null)}
                >
                  <EditableCell value={v} color={theme.pink}
                    highlight={hoveredCol === i}
                    glowColor={theme.pink}
                    onCommit={val => updateB(i, val)} />
                </div>
              ))}
            </div>
            <div style={{ display: 'flex', gap: 3 }}>
              <SizeBtn label="+" onClick={() => vecB.length < 6 && setVecB([...vecB, 0])} disabled={vecB.length >= 6} />
              <SizeBtn label="-" onClick={() => vecB.length > 1 && setVecB(vecB.slice(0, -1))} disabled={vecB.length <= 1} />
            </div>
          </div>

          {/* Equals signs */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
            <div style={{ width: 32 }} />
            <div style={{ display: 'flex', gap: 6 }}>
              {Array.from({ length: maxCols }).map((_, i) => (
                <div key={i} style={{
                  width: 52, textAlign: 'center', fontSize: 18, fontWeight: 400,
                  color: hoveredCol === i ? theme.text : theme.muted,
                  transition: 'color 0.3s',
                }}>=</div>
              ))}
            </div>
          </div>

          {/* Result row */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <div style={{
              width: 32, fontSize: 13, fontWeight: 700,
              color: isValid ? theme.green : theme.red, textAlign: 'right',
            }}>{isValid ? 'c =' : ''}</div>
            <div style={{ display: 'flex', gap: 6, flex: 1 }}>
              {isValid ? result.map((v, i) => (
                <div key={i}
                  onMouseEnter={() => setHoveredCol(i)}
                  onMouseLeave={() => setHoveredCol(null)}
                >
                  <ResultCell value={v} highlight={hoveredCol === i} />
                </div>
              )) : (
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 8,
                  padding: '12px 16px', background: theme.red + '12',
                  border: '2px solid ' + theme.red + '40', borderRadius: 10,
                  fontSize: 14, fontWeight: 700, color: theme.red,
                }}>
                  <span style={{ fontSize: 20 }}>-1</span>
                  <span style={{ fontSize: 11, fontWeight: 500, color: theme.red + 'bb' }}>
                    Dimension mismatch ({vecA.length} vs {vecB.length})
                  </span>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Bar chart */}
        <div style={{
          background: theme.surface, borderRadius: 14, padding: '12px 8px 4px',
          border: '1px solid ' + theme.border, marginTop: 12,
        }}>
          <div style={{ display: 'flex', gap: 16, marginBottom: 4, marginLeft: 12 }}>
            {[{ c: theme.blue, l: 'a' }, { c: theme.pink, l: 'b' }, { c: theme.green, l: 'a + b' }].map(x => (
              <div key={x.l} style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 10, color: theme.textSec }}>
                <div style={{ width: 10, height: 10, borderRadius: 3, background: x.c }} />
                {x.l}
              </div>
            ))}
          </div>
          <BarChart vecA={vecA} vecB={vecB} result={result}
            hoveredCol={hoveredCol} setHoveredCol={setHoveredCol} isValid={isValid} />
        </div>

        {/* Insight */}
        <div style={{
          marginTop: 12, padding: '10px 14px',
          background: theme.surface, borderRadius: 10,
          border: '1px solid ' + theme.border,
          borderLeft: '3px solid ' + (isValid ? (hoveredCol !== null ? theme.primary : theme.green) : theme.red),
          fontSize: 12, color: theme.textSec, lineHeight: 1.5,
          transition: 'border-color 0.3s',
        }}>
          {insight}
        </div>
      </div>
    </div>
  );
}
